def hash_password(password, salt=None):
    if salt is None:
        salt = secrets.token_hex(16)
    hashed = hashlib.pbkdf2_hmac('sha256', password.encode(), salt.encode(), 100000)
    return f"{salt}:{hashed.hex()}"


def verify_password(stored_password, provided_password):
    salt, hashed = stored_password.split(':')
    expected = hashlib.pbkdf2_hmac('sha256', provided_password.encode(), salt.encode(), 100000)
    return hmac.compare_digest(hashed, expected.hex())


def generate_secure_token():
    return secrets.token_urlsafe(48)


def rate_limit_check(key, max_requests=RATE_LIMIT_MAX_REQUESTS, window=RATE_LIMIT_WINDOW):
    now = time.time()
    if key not in rate_limit_store:
        rate_limit_store[key] = []
    # Clean old entries
    rate_limit_store[key] = [t for t in rate_limit_store[key] if now - t < window]
    if len(rate_limit_store[key]) >= max_requests:
        return False
    rate_limit_store[key].append(now)
    return True


def send_email(to_email, subject, body):
    """Send email via SMTP. In production, use a proper email service."""
    try:
        msg = MIMEText(body, 'html')
        msg['Subject'] = subject
        msg['From'] = FROM_EMAIL
        msg['To'] = to_email

        with smtplib.SMTP(SMTP_HOST, SMTP_PORT) as server:
            server.starttls()
            if SMTP_USER and SMTP_PASS:
                server.login(SMTP_USER, SMTP_PASS)
            server.sendmail(FROM_EMAIL, [to_email], msg.as_string())
        return True
    except Exception as e:
        app.logger.error(f"Failed to send email: {e}")
        return False


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        if not session.get('fully_authenticated', False):
            return jsonify({'error': 'Full authentication required (including MFA if enabled)'}), 401
        user = users_db.get(session['user_id'])
        if not user:
            session.clear()
            return jsonify({'error': 'User not found'}), 401
        g.current_user = user
        g.current_user_id = session['user_id']
        return f(*args, **kwargs)
    return decorated_function


def password_authenticated_required(f):
    """Requires password authentication but NOT necessarily MFA completion.
    Used only for the MFA verification step itself."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        if not session.get('password_verified', False):
            return jsonify({'error': 'Password authentication required'}), 401
        user = users_db.get(session['user_id'])
        if not user:
            session.clear()
            return jsonify({'error': 'User not found'}), 401
        g.current_user = user
        g.current_user_id = session['user_id']
        return f(*args, **kwargs)
    return decorated_function


