@app.route('/verify-mfa', methods=['POST'])
@password_authenticated_required
def verify_mfa():
    """Verify MFA code during login."""
    if not session.get('mfa_required', False):
        return jsonify({'error': 'MFA verification not required'}), 400

    if session.get('fully_authenticated', False):
        return jsonify({'message': 'Already fully authenticated'}), 200

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    mfa_code = data.get('mfa_code', '').strip()
    if not mfa_code:
        return jsonify({'error': 'MFA code is required'}), 400

    user = g.current_user
    user_id = g.current_user_id

    if not rate_limit_check(f"mfa_verify:{user_id}", max_requests=5, window=300):
        session.clear()
        return jsonify({'error': 'Too many MFA attempts. Session invalidated.'}), 429

    if not user['mfa_enabled'] or not user['mfa_secret']:
        session['fully_authenticated'] = True
        session['mfa_required'] = False
        return jsonify({'message': 'MFA not enabled, login complete'}), 200

    totp = pyotp.TOTP(user['mfa_secret'])
    # valid_window=1 allows for slight time drift (30 seconds before/after)
    if totp.verify(mfa_code, valid_window=1):
        session['fully_authenticated'] = True
        session['mfa_required'] = False
        return jsonify({'message': 'MFA verified. Login successful.'}), 200
    else:
        return jsonify({'error': 'Invalid MFA code'}), 401


@app.route('/enable-mfa', methods=['POST'])
@login_required
def enable_mfa():
    """Start MFA setup - generates a secret and returns provisioning URI."""
    user = g.current_user
    user_id = g.current_user_id

    if user['mfa_enabled'] and user['mfa_verified']:
        return jsonify({'error': 'MFA is already enabled'}), 400

    # Generate new MFA secret
    mfa_secret = pyotp.random_base32()

    # Store the secret temporarily - don't enable MFA until verified
    setup_token = generate_secure_token()
    mfa_setup_tokens_db[setup_token] = {
        'user_id': user_id,
        'mfa_secret': mfa_secret,
        'created_at': datetime.utcnow(),
        'expires_at': datetime.utcnow() + timedelta(minutes=10),
    }

    totp = pyotp.TOTP(mfa_secret)
    provisioning_uri = totp.provisioning_uri(
        name=user['email'],
        issuer_name='SecureApp'
    )

    return jsonify({
        'message': 'Scan the QR code with your authenticator app, then confirm with a code.',
        'secret': mfa_secret,
        'provisioning_uri': provisioning_uri,
        'setup_token': setup_token,
    }), 200


