@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    """
    Request MFA reset - sends a reset link to the registered email.
    This does NOT immediately disable MFA. The user must click the link
    sent to their verified email address.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = data.get('email', '').strip().lower()
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Rate limit reset requests per email
    if not rate_limit_check(f"mfa_reset:{email}", max_requests=RATE_LIMIT_MAX_REQUESTS, window=RATE_LIMIT_WINDOW):
        return jsonify({'error': 'Too many reset requests. Please try again later.'}), 429

    # Rate limit by IP as well
    client_ip = request.remote_addr
    if not rate_limit_check(f"mfa_reset_ip:{client_ip}", max_requests=5, window=RATE_LIMIT_WINDOW):
        return jsonify({'error': 'Too many reset requests. Please try again later.'}), 429

    # Always return the same response to prevent email enumeration
    generic_response = {
        'message': 'If an account with that email exists and has MFA enabled, a reset link has been sent.'
    }

    # Find user by email
    user_id = None
    user = None
    for uid, u in users_db.items():
        if u['email'] == email:
            user_id = uid
            user = u
            break

    if not user:
        # Don't reveal that the user doesn't exist
        return jsonify(generic_response), 200

    if not user['mfa_enabled']:
        # Don't reveal MFA status
        return jsonify(generic_response), 200

    # Invalidate any existing reset tokens for this user
    tokens_to_remove = [
        token for token, data in reset_tokens_db.items()
        if data['user_id'] == user_id
    ]
    for token in tokens_to_remove:
        del reset_tokens_db[token]

    # Generate a secure reset token
    reset_token = generate_secure_token()
    token_hash = hashlib.sha256(reset_token.encode()).hexdigest()

    reset_tokens_db[token_hash] = {
        'user_id': user_id,
        'email': email,
        'created_at': datetime.utcnow(),
        'expires_at': datetime.utcnow() + timedelta(minutes=RESET_TOKEN_EXPIRY_MINUTES),
        'used': False,
    }

    # Send reset email
    reset_link = f"{BASE_URL}/confirm-mfa-reset?token={reset_token}"
    email_body = f"""
    <html>
    <body>
        <h2>MFA Reset Request</h2>
        <p>You requested to reset your Multi-Factor Authentication settings.</p>
        <p>Click the link below to confirm the MFA reset. This will disable MFA on your account,
        allowing you to log in with just your password. You can then re-enable MFA from your account settings.</p>
        <p><a href="{reset_link}">Reset MFA</a></p>
        <p>This link expires in {RESET_TOKEN_EXPIRY_MINUTES} minutes.</p>
        <p>If you did not request this, please ignore this email and ensure your account is secure.</p>
        <p><strong>Warning:</strong> After resetting MFA, you will need to re-authenticate with your password
        to access your account.</p>
    </body>
    </html>
    """

    send_email(email, 'MFA Reset Request - SecureApp', email_body)

    return jsonify(generic_response), 200


@app.route('/confirm-mfa-reset', methods=['GET', 'POST'])
def confirm_mfa_reset():
    """
    Confirm MFA reset via the emailed link.
    GET: Shows confirmation page
    POST: Actually performs the reset after user confirms and provides password
    """
    token = request.args.get('token', '') or (request.get_json() or {}).get('token', '')

    if not token:
        return jsonify({'error': 'Reset token is required'}), 400

    # Hash the token to look it up
    token_hash = hashlib.sha256(token.encode()).hexdigest()
    reset_data = reset_tokens_db.get(token_hash)

    if not reset_data:
        return jsonify({'error': 'Invalid or expired reset token'}), 400

    if reset_data['used']:
        return jsonify({'error': 'This reset token has already been used'}), 400

    if datetime.utcnow() > reset_data['expires_at']:
        del reset_tokens_db[token_hash]
        return jsonify({'error': 'Reset token has expired'}), 400

    user_id = reset_data['user_id']
    user = users_db.get(user_id)

    if not user:
        return jsonify({'error': 'User not found'}), 404

    if request.method == 'GET':
        # Return confirmation page info
        return jsonify({
            'message': 'Please confirm MFA reset by providing your password.',
            'email': user['email'],
            'action': 'POST to this endpoint with token and password to confirm reset'
        }), 200

    # POST - require password confirmation before resetting MFA
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    password = data.get('password', '')
    if not password:
        return jsonify({'error': 'Password is required to confirm MFA reset'}), 400

    if not rate_limit_check(f"mfa_reset_confirm:{user_id}", max_requests=5, window=300):
        return jsonify({'error': 'Too many attempts. Please try again later.'}), 429

    if not verify_password(user['password'], password):
        return jsonify({'error': 'Invalid password'}), 401

    # Mark token as used BEFORE making changes (prevent race conditions)
    reset_data['used'] = True

    # Disable MFA
    users_db[user_id]['mfa_enabled'] = False
    users_db[user_id]['mfa_secret'] = None
    users_db[user_id]['mfa_verified'] = False
    users_db[user_id]['mfa_reset_pending'] = False

    # Invalidate all sessions for this user (in production, use proper session management)
    # For now, we just note that MFA was reset

    # Clean up the token
    del reset_tokens_db[token_hash]

    # Send notification email
    notification_body = """
    <html>
    <body>
        <h2>MFA Has Been Reset</h2>
        <p>Your Multi-Factor Authentication has been successfully disabled.</p>
        <p>You can now log in with just your password.</p>
        <p>We strongly recommend re-enabling MFA as soon as possible for account security.</p>
        <p>If you did not perform this action, please change your password immediately
        and contact support.</p>
    </body>
    </html>
    """
    send_email(user['email'], 'MFA Reset Confirmation - SecureApp', notification_body)

    return jsonify({
        'message': 'MFA has been reset successfully. You can now log in with your password. '
                   'Please re-enable MFA for account security.'
    }), 200


